import { Controller, Post, Req, RawBodyRequest, Headers, HttpStatus, HttpException } from '@nestjs/common';
import { StripeWebhookService } from './stripe-webhook.service';

@Controller('webhooks')
export class StripeWebhookController {
  constructor(private readonly stripeWebhookService: StripeWebhookService) {}

  @Post('stripe')
  async handleStripeWebhook(
    @Req() req: RawBodyRequest<Request>,
    @Headers('stripe-signature') signature: string,
  ) {
    if (!req.rawBody) {
      throw new HttpException('Raw body required', HttpStatus.BAD_REQUEST);
    }

    try {
      const event = await this.stripeWebhookService.constructEvent(req.rawBody, signature);

      switch (event.type) {
        case 'payment_intent.succeeded':
          await this.stripeWebhookService.handlePaymentSucceeded(event.data.object);
          break;
        case 'payment_intent.payment_failed':
          await this.stripeWebhookService.handlePaymentFailed(event.data.object);
          break;
        default:
          console.log(`Unhandled event type: ${event.type}`);
      }

      return { received: true };
    } catch (error) {
      throw new HttpException(`Webhook Error: ${error.message}`, HttpStatus.BAD_REQUEST);
    }
  }
}

