```typescript
async handlePaymentSucceeded(paymentIntent: Stripe.PaymentIntent) {
  const orderId = paymentIntent.metadata.orderId;
  if (!orderId) {
    this.logger.error('PaymentIntent sans orderId', paymentIntent.id);
    return;
  }

  const queryRunner = this.connection.createQueryRunner();
  await queryRunner.connect();
  await queryRunner.startTransaction();

  try {
    // 1. Vérifier idempotence : la commande n'est pas déjà payée
    const order = await queryRunner.manager.findOne(Order, {
      where: { id: orderId },
      relations: ['items', 'items.product'],
    });

    if (!order) {
      throw new Error(`Commande ${orderId} introuvable`);
    }

    if (order.status === 'paid') {
      this.logger.warn(`Commande ${orderId} déjà payée, webhook ignoré`);
      await queryRunner.rollbackTransaction();
      return;
    }

    // 2. Mettre à jour la commande
    order.status = 'paid';
    order.paymentIntentId = paymentIntent.id;
    order.paidAt = new Date();
    await queryRunner.manager.save(order);

    // 3. Décrémenter les stocks définitifs (si pas déjà fait)
    for (const item of order.items) {
      const product = item.product;
      product.stock -= item.quantity;
      await queryRunner.manager.save(product);
    }

    // 4. Enregistrer la transaction
    const transaction = this.transactionRepository.create({
      orderId: order.id,
      amount: order.total,
      stripePaymentIntentId: paymentIntent.id,
      status: 'completed',
    });
    await queryRunner.manager.save(transaction);

    await queryRunner.commitTransaction();

    // 5. Envoi email (hors transaction, en asynchrone)
    await this.emailService.sendOrderConfirmation(order.user.email, order);

    this.logger.log(`Commande ${orderId} confirmée avec succès`);
  } catch (error) {
    await queryRunner.rollbackTransaction();
    this.logger.error(`Erreur traitement webhook pour order ${orderId}`, error.stack);
    throw error;
  } finally {
    await queryRunner.release();
  }
}
